import sys

def solve(data: str) -> str:
    lines = data.splitlines()
    facts = {item for item in lines[0].split(',') if item}
    rules = [tuple(rule.split('>', 1)) for rule in lines[1].split()]
    changed = True
    while changed:
        changed = False
        for premise, conclusion in rules:
            if premise in facts and conclusion not in facts:
                facts.add(conclusion); changed = True
    return 'entailed' if lines[2].strip() in facts else 'unknown'

if __name__ == "__main__":
    print(solve(sys.stdin.read()), end="")
